BEGIN TRANSACTION;

-- Table: error_codes
CREATE TABLE error_codes (
    error_code      TEXT PRIMARY KEY,
    error_code_description     TEXT NOT NULL,
    severity        TEXT NOT NULL CHECK (severity IN ('low','medium','high','critical')),
    category        TEXT NOT NULL CHECK (category IN
                    ('Sensorik','Mechanik','Elektrik','Software','Kuehlung','Pneumatik')),
    machine_type_id INTEGER NOT NULL REFERENCES machine_types(machine_type_id)
);

-- Table: event_log
CREATE TABLE event_log (
    event_log_id               INTEGER PRIMARY KEY,
    machine_id       INTEGER NOT NULL REFERENCES machines(machine_id),
    timestamp        TEXT    NOT NULL,
    status           TEXT    NOT NULL CHECK (status IN ('error','maintenance','offline')),
    error_code       TEXT REFERENCES error_codes(error_code),
    downtime_minutes REAL CHECK (downtime_minutes IS NULL OR downtime_minutes >= 0)
);

-- Table: halls
CREATE TABLE halls (
    hall_id   INTEGER PRIMARY KEY,
    hall_name TEXT NOT NULL UNIQUE
);

-- Table: machine_types
CREATE TABLE machine_types (
    machine_type_id   INTEGER PRIMARY KEY,
    machine_type_name TEXT NOT NULL UNIQUE
);

-- Table: machines
CREATE TABLE machines (
    machine_id              INTEGER PRIMARY KEY,
    machine_name            TEXT    NOT NULL UNIQUE,
    machine_type_id INTEGER NOT NULL REFERENCES machine_types(machine_type_id),
    hall_id         INTEGER NOT NULL REFERENCES halls(hall_id),
    manufacturer    TEXT    NOT NULL,
    year_built      INTEGER NOT NULL CHECK (year_built BETWEEN 1990 AND 2026)
);

-- Table: measures
CREATE TABLE measures (
    measure_id          INTEGER PRIMARY KEY,
    machine_id  INTEGER NOT NULL REFERENCES machines(machine_id),
    measure_description TEXT    NOT NULL,
    start_date  TEXT    NOT NULL
);

-- Table: technicians
CREATE TABLE technicians (
    technician_id         INTEGER PRIMARY KEY,
    first_name TEXT NOT NULL,
    last_name  TEXT NOT NULL,
    shift      TEXT NOT NULL CHECK (shift IN ('Frueh','Spaet','Nacht'))
);

-- Table: ticket_types
CREATE TABLE ticket_types (
    ticket_type_id   INTEGER PRIMARY KEY,
    ticket_type_name TEXT NOT NULL UNIQUE
);

-- Table: tickets
CREATE TABLE tickets (
    ticket_id             INTEGER PRIMARY KEY,
    ticket_type_id INTEGER NOT NULL REFERENCES ticket_types(ticket_type_id),
    machine_id     INTEGER NOT NULL REFERENCES machines(machine_id),
    error_code     TEXT REFERENCES error_codes(error_code),
    technician_id  INTEGER REFERENCES technicians(technician_id),
    priority       TEXT NOT NULL CHECK (priority IN ('low','medium','high','critical')),
    ticket_description    TEXT NOT NULL,
    created_at     TEXT NOT NULL,
    assigned_at    TEXT,
    resolved_at    TEXT,
    closed_at      TEXT,
    CHECK (assigned_at IS NULL OR assigned_at >= created_at),
    CHECK (resolved_at IS NULL OR resolved_at >= assigned_at),
    CHECK (closed_at   IS NULL OR closed_at   >= created_at),
    CHECK (technician_id IS NULL OR assigned_at IS NOT NULL)
);

